class Solution:
    def diameterOfBinaryTree(self, root):
        def height(node):
            if node is None:
                return 0
            return 1 + max(height(node.left), height(node.right))
        best = 0
        stack = [root] if root else []
        while stack:
            node = stack.pop()
            best = max(best, height(node.left) + height(node.right))
            if node.left:
                stack.append(node.left)
            if node.right:
                stack.append(node.right)
        return best

