class Solution:
    def diameterOfBinaryTree(self, root):
        self.best = 0
        def depth(node):
            if node is None:
                return 0
            ld = depth(node.left)
            rd = depth(node.right)
            self.best = max(self.best, ld + rd)
            return 1 + max(ld, rd)
        depth(root)
        return self.best

