var diameterOfBinaryTree = function(root) {
    let best = 0;
    const depth = (node) => {
        if (node === null) return 0;
        const ld = depth(node.left);
        const rd = depth(node.right);
        best = Math.max(best, ld + rd);
        return 1 + Math.max(ld, rd);
    };
    depth(root);
    return best;
};
